const FILL_COLORS: [number, number, number][] = [
  [180, 160, 232],
  [160, 138, 218],
  [184, 169, 232],
  [200, 175, 240],
  [150, 128, 210],
  [140, 120, 200],
];

interface Stroke {
  x: number; y: number;
  dx: number; dy: number;
  w: number;
  r: number; g: number; b: number;
  a: number;
}

const FILL_MS = 14000;
const HOLD_MS = 2500;
const FADE_MS = 2000;
const CYCLE = FILL_MS + HOLD_MS + FADE_MS;
const N_STROKES = 900;

export default function SwissAquarelle() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Pre-generate diagonal fill strokes (bottom-left → top-right direction)
    const strokes: Stroke[] = [];
    for (let i = 0; i < N_STROKES; i++) {
      const [r, g, b] = FILL_COLORS[i % FILL_COLORS.length];
      const angle = -Math.PI / 4 + (Math.random() - 0.5) * 0.55;
      const len = 12 + Math.random() * 24;
      strokes.push({
        x: 72 + Math.random() * 658,
        y: 22 + Math.random() * 418,
        dx: Math.cos(angle) * len,
        dy: Math.sin(angle) * len,
        w: 2.5 + Math.random() * 5.5,
        r, g, b,
        a: 0.055 + Math.random() * 0.095,
      });
    }

    function setClip(c: CanvasRenderingContext2D) {
      c.beginPath();
      c.moveTo(PTS[0][0], PTS[0][1]);
      for (let i = 1; i < PTS.length; i++) c.lineTo(PTS[i][0], PTS[i][1]);
      c.closePath();
      c.clip();
    }

    let start: number | null = null;
    let raf: number;

    function frame(ts: number) {
      if (!canvas || !ctx) return;
      if (!start) start = ts;
      const elapsed = (ts - start) % CYCLE;

      let count: number;
      let alpha: number;

      if (elapsed < FILL_MS) {
        count = Math.floor((elapsed / FILL_MS) * N_STROKES);
        alpha = 0.5;
      } else if (elapsed < FILL_MS + HOLD_MS) {
        count = N_STROKES;
        alpha = 0.5;
      } else {
        count = N_STROKES;
        alpha = 0.5 * (1 - (elapsed - FILL_MS - HOLD_MS) / FADE_MS);
      }

      ctx.clearRect(0, 0, 800, 460);
      ctx.save();
      setClip(ctx);

      for (let i = 0; i < count; i++) {
        const s = strokes[i];
        ctx.strokeStyle = `rgba(${s.r},${s.g},${s.b},${s.a})`;
        ctx.lineWidth = s.w;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(s.x, s.y);
        ctx.lineTo(s.x + s.dx, s.y + s.dy);
        ctx.stroke();
      }

      ctx.restore();
      canvas.style.opacity = String(Math.max(0, alpha));
      raf = requestAnimationFrame(frame);
    }

    raf = requestAnimationFrame(frame);
    return () => cancelAnimationFrame(raf);
  }, []);

  return (
    <canvas
      ref={canvasRef}
      width={800}
      height={460}
      style={{
        width: '480px',
        height: '280px',
        position: 'absolute',
        left: '50%',
        top: 0,
        transform: 'translateX(-50%)',
        zIndex: 1,
        opacity: 0.5,
        pointerEvents: 'none',
      }}
    />
  );
}
